import{_ as e,o as s,c as i,ai as l}from"./chunks/framework.CsYGeNYI.js";const u=JSON.parse('{"title":"Gateway 网关生命周期","description":"","frontmatter":{"read_when":["将 mac 应用与 Gateway 网关生命周期集成时"],"summary":"macOS 上的 Gateway 网关生命周期（launchd）","title":"Gateway 网关生命周期","x-i18n":{"generated_at":"2026-02-03T07:52:31Z","model":"claude-opus-4-5","provider":"pi","source_hash":"9b910f574b723bc194ac663a5168e48d95f55cb468ce34c595d8ca60d3463c6a","source_path":"platforms/mac/child-process.md","workflow":15}},"headers":[],"relativePath":"zh-CN/platforms/mac/child-process.md","filePath":"zh-CN/platforms/mac/child-process.md","lastUpdated":1771906665000}'),n={name:"zh-CN/platforms/mac/child-process.md"};function t(c,a,d,h,o,p){return s(),i("div",null,[...a[0]||(a[0]=[l(`<h1 id="macos-上的-gateway-网关生命周期" tabindex="-1"><a class="header-anchor" href="#macos-上的-gateway-网关生命周期">#</a> macOS 上的 Gateway 网关生命周期</h1><p>macOS 应用<strong>默认通过 launchd 管理 Gateway 网关</strong>，不会将 Gateway 网关作为子进程生成。它首先尝试连接到配置端口上已运行的 Gateway 网关；如果无法访问，它会通过外部 <code>opensoul</code> CLI（无嵌入式运行时）启用 launchd 服务。这为你提供了可靠的登录时自动启动和崩溃后重启。</p><p>子进程模式（由应用直接生成 Gateway 网关）<strong>目前未使用</strong>。 如果你需要与 UI 更紧密的耦合，请在终端中手动运行 Gateway 网关。</p><h2 id="默认行为-launchd" tabindex="-1"><a class="header-anchor" href="#默认行为-launchd">#</a> 默认行为（launchd）</h2><ul><li>应用安装标记为 <code>ai.opensoul.gateway</code> 的按用户 LaunchAgent （使用 <code>--profile</code>/<code>OPENSOUL_PROFILE</code> 时为 <code>ai.opensoul.&lt;profile&gt;</code>；支持旧版 <code>com.opensoul.*</code>）。</li><li>当启用本地模式时，应用确保 LaunchAgent 已加载，并 在需要时启动 Gateway 网关。</li><li>日志写入 launchd Gateway 网关日志路径（在调试设置中可见）。</li></ul><p>常用命令：</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">launchctl</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> kickstart</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -k</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> gui/</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">$UID</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">/ai.opensoul.gateway</span></span>
<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">launchctl</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> bootout</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> gui/</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">$UID</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">/ai.opensoul.gateway</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br></div></div><p>运行命名配置文件时，将标签替换为 <code>ai.opensoul.&lt;profile&gt;</code>。</p><h2 id="未签名的开发构建" tabindex="-1"><a class="header-anchor" href="#未签名的开发构建">#</a> 未签名的开发构建</h2><p><code>scripts/restart-mac.sh --no-sign</code> 用于在没有签名密钥时的快速本地构建。为了防止 launchd 指向未签名的中继二进制文件，它：</p><ul><li>写入 <code>~/.opensoul/disable-launchagent</code>。</li></ul><p>已签名运行的 <code>scripts/restart-mac.sh</code> 会在标记存在时清除此覆盖。要手动重置：</p><div class="language-bash vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">rm</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ~/.opensoul/disable-launchagent</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br></div></div><h2 id="仅连接模式" tabindex="-1"><a class="header-anchor" href="#仅连接模式">#</a> 仅连接模式</h2><p>要强制 macOS 应用<strong>永不安装或管理 launchd</strong>，请使用 <code>--attach-only</code>（或 <code>--no-launchd</code>）启动它。这会设置 <code>~/.opensoul/disable-launchagent</code>， 因此应用只会连接到已运行的 Gateway 网关。你可以在调试设置中切换相同的 行为。</p><h2 id="远程模式" tabindex="-1"><a class="header-anchor" href="#远程模式">#</a> 远程模式</h2><p>远程模式永远不会启动本地 Gateway 网关。应用使用到 远程主机的 SSH 隧道并通过该隧道连接。</p><h2 id="为什么我们更喜欢-launchd" tabindex="-1"><a class="header-anchor" href="#为什么我们更喜欢-launchd">#</a> 为什么我们更喜欢 launchd</h2><ul><li>登录时自动启动。</li><li>内置的重启/KeepAlive 语义。</li><li>可预测的日志和监管。</li></ul><p>如果将来再次需要真正的子进程模式，它应该被记录为 单独的、明确的仅开发模式。</p>`,20)])])}const k=e(n,[["render",t]]);export{u as __pageData,k as default};
